'@ -split "`n" | ForEach-Object {
    # Trim any leading or trailing whitespace
    $line = $_.Trim()
    
    # Split the line into key and value
    if ($line -match '(\d+)\s*=\s*"([^"]+)"\s*#\s*(.*)') {
        $VSOnlyKeys += [PSCustomObject]@{
            Key         = $matches[1]
            Value       = $matches[2]
            Description = $matches[3]
        }
    }
}

